using UnityEngine;
using UnityEditor;
using UnityEngine.XR.Management;
using UnityEditor.XR.Management;

internal class CommandScript : IRunCommand
{
    public void Execute(ExecutionResult result)
    {
        string path = "Assets/XR/XRGeneralSettingsPerBuildTarget.asset";
        Object asset = AssetDatabase.LoadAssetAtPath<Object>(path);

        if (asset == null)
        {
            result.LogError("Could not load asset at {0}", path);
            return;
        }

        result.Log("Loaded asset: {0} ({1})", asset.name, asset.GetType().FullName);

        if (asset is XRGeneralSettingsPerBuildTarget settings)
        {
            var managerAndroid = settings.SettingsForBuildTarget(BuildTargetGroup.Android);
            CheckManager(managerAndroid, "Android", result);
        }
        else
        {
            result.LogError("Asset is not XRGeneralSettingsPerBuildTarget");
        }
    }

    void CheckManager(XRManagerSettings manager, string platform, ExecutionResult result)
    {
        if (manager == null)
        {
            result.LogWarning("{0} manager is null", platform);
            return;
        }

        result.Log("{0} Manager found: {1}", platform, manager.name);
        // Check for missing scripts in the internal list if possible, or just log what we see.
        SerializedObject so = new SerializedObject(manager);
        SerializedProperty loaders = so.FindProperty("m_Loaders");
        if (loaders != null)
        {
            result.Log("Loaders count: {0}", loaders.arraySize);
            for (int i = 0; i < loaders.arraySize; i++)
            {
                var prop = loaders.GetArrayElementAtIndex(i);
                if (prop.objectReferenceValue == null)
                {
                    result.LogError("Loader at index {0} is MISSING (null reference)!", i);
                }
                else
                {
                    result.Log("Loader {0}: {1}", i, prop.objectReferenceValue.name);
                }
            }
        }
    }
}

